    padding: 8px 20px;
    color: white;
    min-width: 80px;
}
QPushButton:hover {
    background: #5a5a6a;
}

QListView {

    background: #1e1e2e;

    border: 1px solid #4a4a5a;

    border-radius: 8px;

    color: #e0e0e0;

    padding: 5px;

    outline: none;

}

QListView::item {

    padding: 10px 15px;

    border-radius: 6px;

    margin: 2px 4px;

    min-height: 22px;

}

QListView::item:hover {

    background: #3a3a4a;

}

QListView::item:selected {

    background: #6366f1;

    color: white;

}

QPushButton {
    background: #dc3545;
